def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 3:
            score = ratio ** 4 - np.log(ratio) * 3 + np.sqrt(ratio)
            for j in range(1, 5):
                score += ((-1) ** j) * np.sin(ratio * j * np.pi / 2) / (j + 1)
        elif 2 < ratio <= 3:
            val = 0
            for k in range(1, 10):
                val += ((ratio - 2) ** k) / (k ** 2)
            score = val * 15 + np.cos(ratio * np.pi)
        elif 1 < ratio <= 2:
            sum_exp = 0
            for m in range(1, 12):
                sum_exp += np.exp(-m * (2 - ratio)) / m
            score = sum_exp * 8 + np.tan(ratio * np.pi / 4)
        elif 0.5 < ratio <= 1:
            prod_log = 1
            count = 0
            for n in range(1, 15):
                val = ratio + n * 0.03
                if val < 1:
                    prod_log *= np.abs(np.log(1 - val + 1e-14)) ** 1.5
                    count += 1
            score = (1 / (1 - ratio + 1e-14)) * 10 + prod_log * 2 - np.sin(ratio * np.pi * 7)
        elif 0.2 < ratio <= 0.5:
            sum_series = 0
            for p in range(1, 20):
                sum_series += ((-1) ** p) * (ratio ** p) / (p ** 1.5)
            score = sum_series * 20 + np.exp(-ratio * 5)
        else:
            score = 0
            for q in range(1, 25):
                term = np.log(1 + q * ratio + 1e-14) / (q ** 2)
                if term > 0:
                    score += term
                else:
                    score -= term / 2
            score = max(score, 0.1) * 5
        if score < 0:
            score = abs(score) + np.random.uniform(0, 0.2)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority * 4 + np.random.uniform(0, 2)
    else:
        priorities[:] = 1
    return priorities
